- Use the StrReplace tool for edits to existing files
- Use the Write tool only for brand new files
- Read each file before editing it
- Do NOT use shell commands to write files

Port the plugin discovery logic from `submodule/plugins/index.ts` into the ai-pkgs CLI.

## Context
The CLI lives at `/Users/bytedance/dev/ai-skills/apps/cli/`. We're adding plugin management. The reference implementation is at `/Users/bytedance/dev/ai-skills/submodule/plugins/index.ts` (a bundled single-file CLI).

## Task: Create `apps/cli/src/plugins/discover.ts`

Port the discovery functions from `submodule/plugins/index.ts` into a clean TypeScript module. The discovery logic should:

1. Look for `marketplace.json` in multiple locations
2. Check if a directory is a plugin
3. Inspect plugin directories for their contents
4. Recursively scan for plugins

### Types to import

Import these from `./types` (which will exist at `apps/cli/src/plugins/types.ts`):

```typescript
import type {
  DiscoveredPlugin,
  PluginSkill,
  PluginCommand,
  PluginAgent,
  PluginRule,
} from './types';
```

### Functions to implement

Use `node:fs/promises` for `readFile`, `readdir`, `stat` and `node:fs` for `existsSync`. Use `node:path` for `join`, `basename`.

**`discoverPlugins(rootDir: string): Promise<DiscoverResult>`**
Main entry point. Returns `{ plugins, remotePlugins, missingPaths }`.

Discovery priority:
1. Look for `marketplace.json` in: root, `.plugin/`, `.claude-plugin/`, `.cursor-plugin/`, `.codex-plugin/`
2. If found, call `discoverFromMarketplace`
3. If root is a plugin dir, inspect it
4. Otherwise recursively scan subdirs up to depth 2

**`isPluginDir(dirPath: string): Promise<boolean>`**
Check if dir has any of: `.plugin/plugin.json`, `.claude-plugin/plugin.json`, `.cursor-plugin/plugin.json`, `.codex-plugin/plugin.json`, `skills/` dir, `commands/` dir, `agents/` dir, `SKILL.md` file.

**`inspectPlugin(pluginPath: string): Promise<DiscoveredPlugin | null>`**
Read plugin manifest from vendor dirs, discover skills/commands/agents/rules, check for hooks/mcp/lsp.

**`discoverSkills(pluginPath: string): Promise<PluginSkill[]>`**
Scan `skills/` subdir for `SKILL.md` files. Fall back to root `SKILL.md`.

**`discoverCommands(pluginPath: string): Promise<PluginCommand[]>`**
Scan `commands/` for `.md`/`.mdc`/`.markdown` files.

**`discoverAgents(pluginPath: string): Promise<PluginAgent[]>`**
Scan `agents/` for `.md`/`.mdc`/`.markdown` files with name+description in frontmatter.

**`discoverRules(pluginPath: string): Promise<PluginRule[]>`**
Scan `rules/` for `.mdc`/`.md`/`.markdown` files.

**`parseFrontmatter(content: string): Record<string, string | boolean>`**
Parse simple YAML-like frontmatter between `---` markers. Extract key-value pairs.

### Helper types

```typescript
/** Result of plugin discovery in a source tree. */
export type DiscoverResult = {
  plugins: DiscoveredPlugin[];
  remotePlugins: RemotePlugin[];
  missingPaths: string[];
};

/** A plugin declared in marketplace.json but hosted elsewhere. */
export type RemotePlugin = {
  name: string;
  description?: string;
  source: unknown;
};
```

### Reference implementation

Here are the key functions from `submodule/plugins/index.ts` to port. Adapt them to use proper TypeScript types and the project's coding style:

```javascript
// From submodule/plugins/index.ts - DISCOVER
async function discover(repoPath) {
  const marketplacePaths = [
    join(repoPath, "marketplace.json"),
    join(repoPath, ".plugin", "marketplace.json"),
    join(repoPath, ".claude-plugin", "marketplace.json"),
    join(repoPath, ".cursor-plugin", "marketplace.json"),
    join(repoPath, ".codex-plugin", "marketplace.json")
  ];
  for (const mp of marketplacePaths) {
    if (await fileExists(mp)) {
      const data = await readJson(mp);
      if (data && typeof data === "object" && "plugins" in data && Array.isArray(data.plugins)) {
        return discoverFromMarketplace(repoPath, data);
      }
    }
  }
  if (await isPluginDir(repoPath)) {
    const plugin = await inspectPlugin(repoPath);
    return { plugins: plugin ? [plugin] : [], remotePlugins: [], missingPaths: [] };
  }
  const plugins = [];
  await scanForPlugins(repoPath, plugins, 2);
  return { plugins, remotePlugins: [], missingPaths: [] };
}

// SCAN
async function scanForPlugins(dirPath, results, depth) {
  if (depth <= 0) return;
  const entries = await readDirSafe(dirPath);
  for (const entry of entries) {
    if (!entry.isDirectory() || entry.name.startsWith(".")) continue;
    const childPath = join(dirPath, entry.name);
    if (await isPluginDir(childPath)) {
      const plugin = await inspectPlugin(childPath);
      if (plugin) results.push(plugin);
    } else {
      await scanForPlugins(childPath, results, depth - 1);
    }
  }
}

// MARKETPLACE
async function discoverFromMarketplace(repoPath, marketplace) {
  const plugins = [];
  const remotePlugins = [];
  const missingPaths = [];
  const root = marketplace.metadata?.pluginRoot ?? ".";
  for (const entry of marketplace.plugins) {
    if (typeof entry.source !== "string") {
      remotePlugins.push({
        name: entry.name,
        description: entry.description || undefined,
        source: entry.source
      });
      continue;
    }
    const sourcePath = join(repoPath, root, entry.source.replace(/^\.\//, ""));
    if (!await dirExists(sourcePath)) {
      missingPaths.push(entry.source);
      continue;
    }
    // ... inspect skills, manifest, commands, agents, rules, hooks, mcp, lsp
    // ... build DiscoveredPlugin
  }
  return { plugins, remotePlugins, missingPaths };
}

// IS PLUGIN DIR
async function isPluginDir(dirPath) {
  const checks = [
    join(dirPath, ".plugin", "plugin.json"),
    join(dirPath, ".claude-plugin", "plugin.json"),
    join(dirPath, ".cursor-plugin", "plugin.json"),
    join(dirPath, ".codex-plugin", "plugin.json"),
    join(dirPath, "skills"),
    join(dirPath, "commands"),
    join(dirPath, "agents"),
    join(dirPath, "SKILL.md")
  ];
  for (const check of checks) {
    if (await pathExists(check)) return true;
  }
  return false;
}

// INSPECT
async function inspectPlugin(pluginPath) {
  let manifest = null;
  for (const manifestDir of [".plugin", ".claude-plugin", ".cursor-plugin", ".codex-plugin"]) {
    const manifestPath = join(pluginPath, manifestDir, "plugin.json");
    if (await fileExists(manifestPath)) {
      manifest = await readJson(manifestPath);
      break;
    }
  }
  const name = manifest?.name ?? dirName(pluginPath);
  const [skills, commands, agents, rules, hasHooks, hasMcp, hasLsp] = await Promise.all([
    discoverSkills(pluginPath),
    discoverCommands(pluginPath),
    discoverAgents(pluginPath),
    discoverRules(pluginPath),
    fileExists(join(pluginPath, "hooks", "hooks.json")),
    fileExists(join(pluginPath, ".mcp.json")),
    fileExists(join(pluginPath, ".lsp.json"))
  ]);
  return {
    name, version: manifest?.version, description: manifest?.description,
    path: pluginPath, marketplace: undefined,
    skills, commands, agents, rules, hasHooks, hasMcp, hasLsp,
    manifest, explicitSkillPaths: undefined, marketplaceEntry: undefined
  };
}

// FRONTMATTER
function parseFrontmatter(content) {
  const match = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!match?.[1]) return {};
  const result = {};
  for (const line of match[1].split("\n")) {
    const kv = line.match(/^(\w[\w-]*):\s*(.+)$/);
    if (kv) {
      let val = kv[2].trim();
      if (val.startsWith('"') && val.endsWith('"') || val.startsWith("'") && val.endsWith("'")) {
        val = val.slice(1, -1);
      }
      if (val === "true") { result[kv[1]] = true; }
      else if (val === "false") { result[kv[1]] = false; }
      else { result[kv[1]] = val; }
    }
  }
  return result;
}
