/**
 * Install plugins to the specified target agents. Dispatches to
 * per-target strategies with staging workspaces.
 */
export const installPlugins = async (
  plugins: DiscoveredPlugin[],
  target: PluginTarget,
  scope: string,
  repoPath: string,
  source: string
): Promise<void> => {
  switch (target.id) {
    case 'claude-code': {
      // try official CLI first, then fallback
      const workspace = await stageInstallWorkspace(plugins, repoPath, target.id);
      await installToClaudeCode(workspace.plugins, scope, workspace.repoPath, source);
      break;
    }
    case 'cursor': {
      const workspace = await stageInstallWorkspace(plugins, repoPath, target.id);
      await installToCursor(workspace.plugins, scope, workspace.repoPath, source);
      break;
    }
    case 'codex': {
      const workspace = await stageInstallWorkspace(plugins, repoPath, target.id);
      await installToCodex(workspace.plugins, scope, workspace.repoPath, source);
      break;
    }
    default:
      throw new Error(`Unsupported plugin target: ${target.id}`);
  }
};
