import { mkdir, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

/** Options for scaffolding a new plugin. */
export type InitPluginOptions = {
  name: string;
  directory: string;
  agents: string[];
  components: string[];
};

/**
 * Scaffold a new plugin directory with vendor manifests and component stubs.
 */
export const initPlugin = async (options: InitPluginOptions): Promise<string> => {
  const pluginDir = options.directory;
  await mkdir(pluginDir, { recursive: true });

  // Generate vendor-specific plugin manifests
  const manifest = {
    name: options.name,
    description: '',
    version: '0.0.1',
  };

  for (const agent of options.agents) {
    const vendorDir = agentToVendorDir(agent);
    if (vendorDir) {
      const dir = join(pluginDir, vendorDir);
      await mkdir(dir, { recursive: true });
      await writeFile(
        join(dir, 'plugin.json'),
        JSON.stringify(manifest, null, 2) + '\n',
      );
    }
  }

  // Generate component stubs
  for (const component of options.components) {
    await generateComponentStub(pluginDir, options.name, component);
  }

  // Generate README
  await writeFile(
    join(pluginDir, 'README.md'),
    generateReadme(options.name),
  );

  return pluginDir;
};

