import { existsSync } from 'node:fs';
import { readFile, rm, writeFile } from 'node:fs/promises';
import { homedir } from 'node:os';
import { join } from 'node:path';
import { deriveMarketplaceName } from './claude';

/**
 * Remove a Claude Code plugin from the cache, `installed_plugins.json`,
 * and `settings.json` `enabledPlugins`.
 *
 * When `projectDir` is provided the settings cleanup targets the
 * project-scoped `.claude/settings.json`; otherwise the global one.
 */
export const uninstallFromClaude = async (
  pluginName: string,
  marketplaceName: string,
  projectDir?: string
): Promise<void> => {
  const home = homedir();
  const pluginsDir = join(home, '.claude', 'plugins');
  const cacheDir = join(pluginsDir, 'cache', marketplaceName, pluginName);

  if (existsSync(cacheDir)) {
    await rm(cacheDir, { recursive: true });
  }

  const installedPath = join(pluginsDir, 'installed_plugins.json');
  if (existsSync(installedPath)) {
    try {
      const data = JSON.parse(await readFile(installedPath, 'utf-8'));
      const pluginKey = `${pluginName}@${marketplaceName}`;
      if (data.plugins && data.plugins[pluginKey]) {
        delete data.plugins[pluginKey];
        await writeFile(installedPath, JSON.stringify(data, null, 2));
      }
    } catch {
      // corrupted file – skip
    }
  }

  const settingsPath = projectDir
    ? join(projectDir, '.claude', 'settings.json')
    : join(home, '.claude', 'settings.json');

  if (existsSync(settingsPath)) {
    try {
      const settings = JSON.parse(await readFile(settingsPath, 'utf-8'));
      const enabled = settings.enabledPlugins as
        | Record<string, boolean>
        | undefined;
      if (enabled) {
        const pluginKey = `${pluginName}@${marketplaceName}`;
        delete enabled[pluginKey];
        await writeFile(settingsPath, JSON.stringify(settings, null, 2));
      }
    } catch {
      // corrupted file – skip
    }
  }
};

/**
 * Remove a Cursor plugin. On Windows, cleans `~/.cursor/extensions/` and
 * `extensions.json`. On other platforms, delegates to Claude cache cleanup
 * since Cursor shares it.
 */
export const uninstallFromCursor = async (
  pluginName: string,
  marketplaceName: string
): Promise<void> => {
  if (process.platform === 'win32') {
    const home = homedir();
    const extensionsDir = join(home, '.cursor', 'extensions');
    const extensionsJsonPath = join(extensionsDir, 'extensions.json');

    if (existsSync(extensionsJsonPath)) {
      try {
        const parsed = JSON.parse(
          await readFile(extensionsJsonPath, 'utf-8')
        );
        if (Array.isArray(parsed)) {
          const identifier = `${marketplaceName}.${pluginName}`;
          const filtered = parsed.filter(
            (e: Record<string, unknown>) =>
              (e?.identifier as Record<string, unknown> | undefined)?.id !==
              identifier
          );
          await writeFile(
            extensionsJsonPath,
            JSON.stringify(filtered, null, 2)
          );

          const folderPrefix = `${marketplaceName}.${pluginName}-`;
          const { readdirSync } = await import('node:fs');
          for (const entry of readdirSync(extensionsDir)) {
            if (entry.startsWith(folderPrefix)) {
              await rm(join(extensionsDir, entry), { recursive: true });
            }
          }
        }
      } catch {
        // corrupted file – skip
      }
    }
    return;
  }

  await uninstallFromClaude(pluginName, marketplaceName);
};

/**
 * Remove a Codex plugin from its cache, `config.toml`, and the global
 * `~/.agents/plugins/marketplace.json`.
 */
export const uninstallFromCodex = async (
  pluginName: string,
  marketplaceName: string
): Promise<void> => {
  const home = homedir();
  const cacheDir = join(
    home,
    '.codex',
    'plugins',
    'cache',
    marketplaceName,
    pluginName
  );

  if (existsSync(cacheDir)) {
    await rm(cacheDir, { recursive: true });
  }

  const configPath = join(home, '.codex', 'config.toml');
  if (existsSync(configPath)) {
    try {
      let content = await readFile(configPath, 'utf-8');
      const pluginKey = `${pluginName}@plugins-cli`;
      const sectionRegex = new RegExp(
        `\\n?\\[plugins\\."${escapeRegex(pluginKey)}"\\]\\nenabled = (?:true|false)\\n?`,
        'g'
      );
      const updated = content.replace(sectionRegex, '\n');
      if (updated !== content) {
        await writeFile(configPath, updated.replace(/^\n+/, ''));
      }
    } catch {
      // corrupted file – skip
    }
  }

  const marketplacePath = join(home, '.agents', 'plugins', 'marketplace.json');
  if (existsSync(marketplacePath)) {
    try {
      const data = JSON.parse(await readFile(marketplacePath, 'utf-8'));
      if (Array.isArray(data.plugins)) {
        data.plugins = data.plugins.filter(
          (e: Record<string, unknown>) => e.name !== pluginName
        );
        await writeFile(marketplacePath, JSON.stringify(data, null, 2));
      }
    } catch {
      // corrupted file – skip
    }
  }
};

/**
 * Uninstall a plugin from one target agent. Derives the marketplace name
 * from the source string.
 */
export const uninstallPlugins = async (
  pluginName: string,
  source: string,
  target: string,
  projectDir?: string
): Promise<void> => {
  const marketplaceName = deriveMarketplaceName(source);

  switch (target) {
    case 'claude-code':
      await uninstallFromClaude(pluginName, marketplaceName, projectDir);
      break;
    case 'cursor':
      await uninstallFromCursor(pluginName, marketplaceName);
      break;
    case 'codex':
      await uninstallFromCodex(pluginName, marketplaceName);
      break;
    default:
      throw new Error(`Unsupported uninstall target: ${target}`);
  }
};

const escapeRegex = (str: string): string =>
  str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

import * as p from '@clack/prompts';
import pc from 'picocolors';
import type { GitProgressEvent } from '../git';
import { renderAiDone, renderAiStep } from './ai-output';

/** Callbacks returned by {@link createCloneProgressRenderer}. */
export type CloneProgressRenderer = {
  onProgress?: (event: GitProgressEvent) => void;
  done: (ref?: string, commitSha?: string) => void;
  fail: (error: unknown) => void;
};

/**
 * Create a renderer that formats Git clone/cache progress events for
 * spinner, AI, or plain-text output modes.
 *
 * Shared between `skills add` and `plugins add` so both display consistent
 * clone feedback.
 *
 * @example
 * ```ts
 * const renderer = createCloneProgressRenderer({ aiMode: false, enabled: true, verbose: false });
 * const resolved = await registry.resolve({ onProgress: renderer.onProgress });
 * renderer.done(resolved.ref, resolved.commitSha);
 * ```
 */
export const createCloneProgressRenderer = ({
  aiMode,
  enabled,
  verbose,
}: {
  aiMode: boolean;
  enabled: boolean;
  verbose: boolean;
}): CloneProgressRenderer => {
  if (!enabled) {
    return {
      done: () => {},
      fail: () => {},
    };
  }

  if (aiMode) {
    let usedCache = false;
    return {
      onProgress: (event) => {
        if (event.status === 'cache-hit') {
          usedCache = true;
        }
        const message = formatCloneProgress(event);
        if (message) {
          process.stdout.write(renderAiStep(message));
        }
      },
      done: (ref, commitSha) => {
        if (usedCache) {
          return;
        }
        process.stdout.write(renderAiDone(formatCloneDone(ref, commitSha)));
      },
      fail: () => {},
    };
  }

  if (process.stdin.isTTY !== true) {
    return {
      done: () => {},
      fail: () => {},
    };
  }

  const spinner = p.spinner();
  let started = false;
  let completed = false;

  return {
    onProgress: (event) => {
      if (isCacheProgressEvent(event)) {
        const message = formatCloneProgress(event);
        if (started && event.status === 'cache-store') {
          started = false;
          completed = true;
          spinner.stop(formatCloneDone(event.ref, event.commitSha));
        }
        if (message) {
          p.note(message, 'Git cache');
        }
        return;
      }

      if (event.status === 'cloning') {
        started = true;
        spinner.start(`Cloning repository: ${event.cloneUrl}`);
        return;
      }

      const message = formatCloneProgress(event);
      if (message && started) {
        spinner.message(message);
      } else if (message && verbose) {
        p.log.info(message);
      }
    },
    done: (ref, commitSha) => {
      if (started && !completed) {
        spinner.stop(formatCloneDone(ref, commitSha));
      }
    },
    fail: () => {
      if (started) {
        spinner.stop(pc.red('Failed to clone repository'));
      }
    },
  };
};

/**
 * Check whether an event belongs to the Git-cache family
 * (`cache-hit`, `cache-refresh`, `cache-store`).
 */
export const isCacheProgressEvent = (
  event: GitProgressEvent
): event is Extract<
  GitProgressEvent,
  { status: 'cache-hit' | 'cache-refresh' | 'cache-store' }
> =>
  event.status === 'cache-hit' ||
  event.status === 'cache-refresh' ||
  event.status === 'cache-store';

/**
 * Format Git resolve, clone, and cache events for spinner/static output.
 */
export const formatCloneProgress = (event: GitProgressEvent): string => {
  if (event.status === 'resolving-remote') {
    return `resolving remote ref: ${event.ref ?? 'HEAD'}`;
  }
  if (event.status === 'cloning') {
    return `cloning repository: ${event.cloneUrl}`;
  }
  if (event.status === 'checking-out') {
    return event.commitSha
      ? `checking out commit: ${shortSha(event.commitSha)}`
      : `checking out ref: ${event.ref ?? 'HEAD'}`;
  }
  if (event.status === 'resolved') {
    return `resolving git pin: ${event.ref}@${shortSha(event.commitSha)}`;
  }
  if (event.status === 'cache-hit') {
    return [
      'reusing Git cache for verified remote ref',
      `source: ${event.provider}:${event.packageId}`,
      `ref: ${event.ref}@${shortSha(event.commitSha)}`,
      `cache: ${event.cachePath}`,
    ].join('\n');
  }
  if (event.status === 'cache-refresh') {
    return `refreshing Git cache: ${event.cachePath}`;
  }
  if (event.status === 'cache-store') {
    return `stored Git cache: ${event.cachePath}`;
  }
  return '';
};

/**
 * Format the terminal clone success message with the pinned Git version.
 */
export const formatCloneDone = (ref?: string, commitSha?: string): string => {
  if (!ref || !commitSha) {
    return 'Repository cloned';
  }
  return `Repository cloned (${ref}@${shortSha(commitSha)})`;
};

const shortSha = (sha: string): string => sha.slice(0, 7);

