import * as p from '@clack/prompts';
import pc from 'picocolors';
import { isAICommand } from '../../cli/ai-mode';
import { SilentError } from '../../errors';
import { resolveRemoteRef, type ResolvedRemoteRef } from '../../git';
import { createManifestStore, resolveManifestScope } from '../../manifest';
import type { PluginEntry } from '../../plugins/types';
import type { PluginsCommandRuntime } from './types';

/**
 * Discriminated union for per-plugin update check outcome.
 */
export type PluginUpdateStatus =
  | {
      status: 'outdated';
      plugin: PluginEntry;
      ref: string;
      currentSha: string;
      latestSha: string;
    }
  | {
      status: 'up-to-date';
      plugin: PluginEntry;
      ref: string;
      currentSha: string;
    }
  | {
      status: 'skipped';
      plugin: PluginEntry;
      reason: string;
    }
  | {
      status: 'failed';
      plugin: PluginEntry;
      reason: string;
    };

/** Aggregated result of an update check across all manifest plugins. */
export type PluginUpdateCheckResult = {
  outdated: Extract<PluginUpdateStatus, { status: 'outdated' }>[];
  upToDate: Extract<PluginUpdateStatus, { status: 'up-to-date' }>[];
  skipped: Extract<PluginUpdateStatus, { status: 'skipped' }>[];
  failed: Extract<PluginUpdateStatus, { status: 'failed' }>[];
};

/** Injectable `resolveRef` for tests. */
export type CheckPluginUpdatesOptions = {
  resolveRef?: (request: {
    provider: 'github' | 'gitlab';
    packageId: string;
    cloneUrl: string;
    ref: string;
  }) => Promise<ResolvedRemoteRef>;
};

/**
 * Check all or selected manifest plugins for Git pin updates.
 *
 * Groups checks by provider + packageId + ref so multiple plugins from the
 * same source perform only one remote lookup.
 */
export const checkPluginUpdates = async (
  plugins: PluginEntry[],
  requestedNames: string[] = [],
  options: CheckPluginUpdatesOptions = {}
): Promise<PluginUpdateCheckResult> => {
  const selected = selectManifestPlugins(plugins, requestedNames);
  const result: PluginUpdateCheckResult = {
    outdated: [],
    upToDate: [],
    skipped: [],
    failed: [],
  };
  const grouped = new Map<string, PluginEntry[]>();

  for (const plugin of selected) {
    if (plugin.provider === 'file') {
      result.skipped.push({
        status: 'skipped',
        plugin,
        reason: 'file sources are not Git-updatable',
      });
      continue;
    }
    if (plugin.provider === 'marketplace') {
      result.skipped.push({
        status: 'skipped',
        plugin,
        reason: 'marketplace updates are not implemented yet',
      });
      continue;
    }
    if (!plugin.ref || !plugin.commitSha) {
      result.failed.push({
        status: 'failed',
        plugin,
        reason: 'missing ref or commitSha in ai-package.json',
      });
      continue;
    }

    const key = `${plugin.provider}\0${plugin.packageId}\0${plugin.ref}`;
    grouped.set(key, [...(grouped.get(key) ?? []), plugin]);
  }

  for (const group of grouped.values()) {
    const first = group[0];
    if (
      !first ||
      (first.provider !== 'github' && first.provider !== 'gitlab')
    ) {
      continue;
    }

    try {
      const latest = await (options.resolveRef ?? defaultResolveRef)({
        provider: first.provider,
        packageId: first.packageId,
        cloneUrl: cloneUrlForPlugin({
          ...first,
          provider: first.provider,
        }),
        ref: first.ref ?? 'HEAD',
      });
      for (const plugin of group) {
        const currentSha = plugin.commitSha ?? '';
        if (latest.commitSha === currentSha) {
          result.upToDate.push({
            status: 'up-to-date',
            plugin,
            ref: latest.ref,
            currentSha,
          });
        } else {
          result.outdated.push({
            status: 'outdated',
            plugin,
            ref: latest.ref,
            currentSha,
            latestSha: latest.commitSha,
          });
        }
      }
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      for (const plugin of group) {
        result.failed.push({ status: 'failed', plugin, reason });
      }
    }
  }

  result.outdated.sort(compareStatuses);
  result.upToDate.sort(compareStatuses);
  result.skipped.sort(compareStatuses);
  result.failed.sort(compareStatuses);
  return result;
};

/**
 * Format plugin update check groups as stable ASCII text.
 */
export const formatPluginUpdateCheckResult = (
  result: PluginUpdateCheckResult,
  options: { includeUpToDate?: boolean } = {}
): string => {
  const lines: string[] = [`outdated: ${result.outdated.length}`];
  for (const item of result.outdated) {
    lines.push(
      `- ${item.plugin.name} ${item.ref}@${shortSha(item.currentSha)} -> ${item.ref}@${shortSha(item.latestSha)}`
    );
  }

  if (options.includeUpToDate !== false) {
    lines.push(`up-to-date: ${result.upToDate.length}`);
    for (const item of result.upToDate) {
      lines.push(
        `- ${item.plugin.name} ${item.ref}@${shortSha(item.currentSha)}`
      );
    }
  }

  lines.push(`skipped: ${result.skipped.length}`);
  for (const item of result.skipped) {
    lines.push(`- ${item.plugin.name} ${item.reason}`);
  }

  if (result.failed.length > 0) {
    lines.push(`failed: ${result.failed.length}`);
    for (const item of result.failed) {
      lines.push(`- ${item.plugin.name} ${item.reason}`);
    }
  }

  return `${lines.join('\n')}\n`;
};

/**
 * Write the plugin update check result to stdout (plain text) or as
 * a Clack note (TTY).
 */
export const writePluginUpdateCheckResult = (
  result: PluginUpdateCheckResult,
  options: { title: string; aiMode: boolean; includeUpToDate?: boolean }
) => {
  const output = formatPluginUpdateCheckResult(result, {
    includeUpToDate: options.includeUpToDate,
  });

  if (!options.aiMode && process.stdin.isTTY === true) {
    p.note(output.trimEnd(), options.title);
    return;
  }

  process.stdout.write(output);
};

/**
 * Apply outdated Git pins to plugin entries without changing skipped entries.
 */
export const applyPluginUpdates = (
  plugins: PluginEntry[],
  result: PluginUpdateCheckResult
): PluginEntry[] => {
  const updatesByName = new Map(
    result.outdated.map((item) => [item.plugin.name, item])
  );

  return plugins.map((plugin): PluginEntry => {
    const update = updatesByName.get(plugin.name);
    if (!update) return plugin;
    return {
      ...plugin,
      version: `${update.ref}@${update.latestSha}`,
      ref: update.ref,
      commitSha: update.latestSha,
    };
  });
};

/**
 * Execute `ai-pkgs plugins outdated`.
 */
export const runPluginsOutdatedCommand = async (
  plugins: string[],
  options: { dir?: string; global?: boolean; manifest?: string; ai?: boolean },
  _runtime: PluginsCommandRuntime
): Promise<number> => {
  const aiMode = isAICommand(options);
  if (!aiMode && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin outdated'));
  }

  const manifestScope = resolveManifestScope(_runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();

  if (manifest.plugins.length === 0) {
    if (aiMode) {
      process.stdout.write('No plugins in ai-package.json\n');
    } else if (process.stdin.isTTY === true) {
      p.log.info('No plugins declared in ai-package.json');
      p.outro('Done.');
    }
    return 0;
  }

  const result = await checkPluginUpdates(manifest.plugins, plugins);
  writePluginUpdateCheckResult(result, {
    title: 'Plugin updates',
    aiMode,
  });

  if (!aiMode && process.stdin.isTTY === true) {
    p.outro(
      result.outdated.length > 0
        ? pc.yellow(
            `${result.outdated.length} plugin${result.outdated.length === 1 ? '' : 's'} can be updated`
          )
        : pc.green('All plugins up to date')
    );
  }

  return result.failed.length > 0 ? 1 : 0;
};

const selectManifestPlugins = (
  plugins: PluginEntry[],
  requestedNames: string[]
): PluginEntry[] => {
  if (requestedNames.length === 0) return plugins;

  const byName = new Map(plugins.map((pl) => [pl.name, pl]));
  const missing = requestedNames.filter((name) => !byName.has(name));
  if (missing.length > 0) {
    throw new SilentError(
      [
        `Unknown plugin name${missing.length === 1 ? '' : 's'}: ${missing.join(', ')}`,
        `Available plugins: ${plugins
          .map((pl) => pl.name)
          .sort()
          .join(', ')}`,
      ].join('\n')
    );
  }

  return requestedNames
    .map((name) => byName.get(name))
    .filter((v): v is PluginEntry => v !== undefined);
};

const defaultResolveRef: NonNullable<
  CheckPluginUpdatesOptions['resolveRef']
> = async ({ cloneUrl, ref }) => resolveRemoteRef({ cloneUrl, ref });

const cloneUrlForPlugin = (
  plugin: PluginEntry & { provider: 'github' | 'gitlab' }
): string => {
  if (plugin.cloneUrl) return plugin.cloneUrl;
  if (plugin.provider === 'github') {
    return `https://github.com/${plugin.packageId.replace(/\.git$/, '')}.git`;
  }
  return plugin.packageId;
};

const compareStatuses = (
  a: Pick<PluginUpdateStatus, 'plugin'>,
  b: Pick<PluginUpdateStatus, 'plugin'>
) => a.plugin.name.localeCompare(b.plugin.name);

const shortSha = (sha: string): string => sha.slice(0, 7);

import * as p from '@clack/prompts';
import pc from 'picocolors';
import { canPrompt, isAICommand } from '../../cli/ai-mode';
import { renderAiDone, renderAiStep } from '../../cli/ai-output';
import { SilentError } from '../../errors';
import { createManifestStore, resolveManifestScope } from '../../manifest';
import { discoverPlugins } from '../../plugins/discover';
import { installPlugins } from '../../plugins/installer';
import type { PluginTarget } from '../../plugins/installer/types';
import type { PluginEntry } from '../../plugins/types';
import {
  applyPluginUpdates,
  checkPluginUpdates,
  formatPluginUpdateCheckResult,
  writePluginUpdateCheckResult,
} from './outdated';
import type { PluginsCommandRuntime, PluginsUpdateOptions } from './types';

/**
 * `ai-pkgs plugins update` checks for outdated Git pins, writes new
 * SHAs to `ai-package.json`, then reinstalls each updated plugin to
 * its persisted targets.
 */
export const runPluginsUpdateCommand = async (
  plugins: string[],
  options: PluginsUpdateOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  const aiMode = isAICommand(options);
  const projectDir = runtime.cwd;

  if (!aiMode && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin update'));
  }

  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();

  if (manifest.plugins.length === 0) {
    if (aiMode) {
      process.stdout.write('No plugins in ai-package.json\n');
    } else if (process.stdin.isTTY === true) {
      p.log.info('No plugins declared in ai-package.json');
      p.outro('Done.');
    }
    return 0;
  }

  const result = await checkPluginUpdates(manifest.plugins, plugins);

  if (result.failed.length > 0) {
    writePluginUpdateCheckResult(result, {
      title: 'Plugin update check failed',
      aiMode,
    });
    if (!aiMode && process.stdin.isTTY === true) {
      p.outro(pc.red('Update check failed'));
    }
    return 1;
  }

  if (result.outdated.length === 0) {
    const output = formatPluginUpdateCheckResult(
      { ...result, upToDate: [] },
      { includeUpToDate: false }
    ).replace(/^outdated:/, 'updated:');
    process.stdout.write(output);
    if (!aiMode && process.stdin.isTTY === true) {
      p.outro(pc.green('All plugins up to date'));
    }
    return 0;
  }

  if (options.yes !== true) {
    if (!canPrompt(options)) {
      throw new SilentError(
        'Pass --yes to update plugins in non-interactive or --ai mode.'
      );
    }
    writePluginUpdateCheckResult(result, {
      title: 'Plugin updates',
      aiMode: false,
      includeUpToDate: false,
    });
    const confirmed = await runtime.confirm({
      message: `Update ${result.outdated.length} plugin${result.outdated.length === 1 ? '' : 's'} in ai-package.json?`,
      initialValue: true,
    });
    if (confirmed !== true) {
      p.cancel('Plugin update cancelled');
      return 1;
    }
  }

  const updatedPlugins = applyPluginUpdates(manifest.plugins, result);
  await store.write({ ...manifest, plugins: updatedPlugins });

  if (aiMode) {
    process.stdout.write(
      renderAiStep(
        `Updated ${result.outdated.length} plugin(s) in ai-package.json`
      )
    );
  } else {
    p.log.success(
      `Updated ${result.outdated.length} plugin(s) in ai-package.json`
    );
  }

  const updatedNames = new Set(
    result.outdated.map((item) => item.plugin.name)
  );
  const pluginsToReinstall = updatedPlugins.filter((pl) =>
    updatedNames.has(pl.name)
  );
  await reinstallPlugins(pluginsToReinstall, projectDir, aiMode);

  const output = formatPluginUpdateCheckResult(
    { ...result, upToDate: [] },
    { includeUpToDate: false }
  ).replace(/^outdated:/, 'updated:');
  process.stdout.write(output);

  if (!aiMode && process.stdin.isTTY === true) {
    p.outro(pc.green('Update complete'));
  }
  return 0;
};

/**
 * Re-resolve and reinstall each updated plugin to its persisted targets.
 */
const reinstallPlugins = async (
  plugins: PluginEntry[],
  projectDir: string,
  aiMode: boolean
): Promise<void> => {
  for (const plugin of plugins) {
    const targets = plugin.targets ?? [];
    if (targets.length === 0) continue;

    const source = plugin.source ?? `${plugin.provider}:${plugin.packageId}`;

    // Re-resolve from registries to get the new version on disk
    const { createRegistries, getRegistry } = await import('../../registries');
    const registries = createRegistries(projectDir);
    const registryKind =
      plugin.provider === 'file'
        ? 'file'
        : plugin.provider === 'github'
          ? 'github'
          : 'gitlab';
    const registry = getRegistry(registries, registryKind);

    let resolved;
    try {
      resolved = await registry.resolve({
        rawSource: source,
        registry: registryKind,
        ref: plugin.ref,
        refresh: true,
      });
    } catch {
      if (aiMode) {
        process.stdout.write(
          renderAiStep(`Failed to resolve ${plugin.name} for reinstall`)
        );
      } else {
        p.log.warn(`Failed to resolve ${plugin.name} for reinstall`);
      }
      continue;
    }

    try {
      const { plugins: discovered } = await discoverPlugins(
        resolved.root.rootDir
      );
      const toInstall =
        discovered.filter((d) => d.name === plugin.name) || discovered;

      if (toInstall.length === 0) {
        await resolved.root.cleanup?.();
        continue;
      }

      for (const targetId of targets) {
        const target: PluginTarget = {
          id: targetId as 'claude-code' | 'cursor' | 'codex',
          name: targetId,
          detected: true,
          configPath: '',
        };

        await installPlugins(
          toInstall,
          target,
          'user',
          resolved.root.rootDir,
          source,
          projectDir
        );

        if (aiMode) {
          process.stdout.write(
            renderAiDone(`Reinstalled ${plugin.name} to ${targetId}`)
          );
        } else {
          p.log.success(`Reinstalled ${plugin.name} to ${targetId}`);
        }
      }
    } finally {
      await resolved.root.cleanup?.();
    }
  }
};

import * as p from '@clack/prompts';
import pc from 'picocolors';
import { canPrompt, isAICommand } from '../../cli/ai-mode';
import { renderAiDone, renderAiStep } from '../../cli/ai-output';
import { SilentError } from '../../errors';
import { createManifestStore, resolveManifestScope } from '../../manifest';
import { discoverPlugins } from '../../plugins/discover';
import { installPlugins } from '../../plugins/installer';
import type { PluginTarget } from '../../plugins/installer/types';
import { uninstallPlugins } from '../../plugins/installer/uninstall';
import { createRegistries, getRegistry } from '../../registries';
import type { PluginsCommandRuntime } from './types';

const VALID_TARGETS = new Set(['claude-code', 'cursor', 'codex']);

/** CLI options for `plugins targets`. */
export type PluginsTargetsOptions = {
  dir?: string;
  global?: boolean;
  manifest?: string;
  yes?: boolean;
  noInstall?: boolean;
  ai?: boolean;
};

/**
 * `plugins targets add <plugin> <agent...>` adds targets to a plugin
 * and optionally installs.
 */
export const runPluginsTargetsAddCommand = async (
  args: string[],
  options: PluginsTargetsOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  const [pluginName, ...agents] = args;
  if (!pluginName || agents.length === 0) {
    throw new SilentError(
      'Usage: ai-pkgs plugins targets add <plugin> <agent...>'
    );
  }

  const aiMode = isAICommand(options);
  if (!aiMode && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin targets add'));
  }

  for (const agent of agents) {
    if (!VALID_TARGETS.has(agent)) {
      throw new SilentError(
        `Invalid target "${agent}". Allowed: claude-code, cursor, codex`
      );
    }
  }

  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();
  const plugin = manifest.plugins.find((pl) => pl.name === pluginName);
  if (!plugin) {
    const available =
      manifest.plugins.map((pl) => pl.name).join(', ') || '(none)';
    throw new SilentError(
      `Plugin "${pluginName}" not found in ai-package.json.\nAvailable: ${available}`
    );
  }

  const existing = new Set(plugin.targets ?? []);
  const newAgents = agents.filter((a) => !existing.has(a));
  for (const agent of agents) {
    existing.add(agent);
  }
  plugin.targets = [...existing].sort();
  await store.write(manifest);

  if (aiMode) {
    process.stdout.write(
      renderAiStep(
        `Updated targets for ${pluginName}: [${plugin.targets.join(', ')}]`
      )
    );
  } else {
    p.log.success(
      `Updated targets for ${pluginName}: [${plugin.targets.join(', ')}]`
    );
  }

  if (options.noInstall === true || newAgents.length === 0) {
    if (!aiMode && process.stdin.isTTY === true) {
      p.outro(pc.green('Done.'));
    }
    return 0;
  }

  let shouldInstall = options.yes === true;
  if (!shouldInstall && canPrompt(options)) {
    const confirmed = await runtime.confirm({
      message: `Install to ${newAgents.join(', ')} now?`,
      initialValue: true,
    });
    shouldInstall = confirmed === true;
  }

  if (shouldInstall) {
    const source = plugin.source ?? `${plugin.provider}:${plugin.packageId}`;
    await installToTargets(
      plugin.name,
      source,
      plugin,
      newAgents,
      runtime.cwd,
      aiMode
    );
  }

  if (!aiMode && process.stdin.isTTY === true) {
    p.outro(pc.green('Done.'));
  }
  return 0;
};

/**
 * `plugins targets remove <plugin> <agent...>` removes targets from a
 * plugin and optionally uninstalls.
 */
export const runPluginsTargetsRemoveCommand = async (
  args: string[],
  options: PluginsTargetsOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  const [pluginName, ...agents] = args;
  if (!pluginName || agents.length === 0) {
    throw new SilentError(
      'Usage: ai-pkgs plugins targets remove <plugin> <agent...>'
    );
  }

  const aiMode = isAICommand(options);
  if (!aiMode && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin targets remove'));
  }

  for (const agent of agents) {
    if (!VALID_TARGETS.has(agent)) {
      throw new SilentError(
        `Invalid target "${agent}". Allowed: claude-code, cursor, codex`
      );
    }
  }

  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();
  const plugin = manifest.plugins.find((pl) => pl.name === pluginName);
  if (!plugin) {
    throw new SilentError(
      `Plugin "${pluginName}" not found in ai-package.json`
    );
  }

  const removeSet = new Set(agents);
  const removedAgents = (plugin.targets ?? []).filter((t) => removeSet.has(t));
  plugin.targets = (plugin.targets ?? []).filter((t) => !removeSet.has(t));
  await store.write(manifest);

  if (aiMode) {
    process.stdout.write(
      renderAiStep(
        `Updated targets for ${pluginName}: [${plugin.targets.join(', ')}]`
      )
    );
  } else {
    p.log.success(
      `Updated targets for ${pluginName}: [${plugin.targets.join(', ')}]`
    );
  }

  if (options.noInstall === true || removedAgents.length === 0) {
    if (!aiMode && process.stdin.isTTY === true) {
      p.outro(pc.green('Done.'));
    }
    return 0;
  }

  let shouldUninstall = options.yes === true;
  if (!shouldUninstall && canPrompt(options)) {
    const confirmed = await runtime.confirm({
      message: `Uninstall from ${removedAgents.join(', ')} now?`,
      initialValue: true,
    });
    shouldUninstall = confirmed === true;
  }

  if (shouldUninstall) {
    const source = plugin.source ?? `${plugin.provider}:${plugin.packageId}`;
    for (const target of removedAgents) {
      try {
        await uninstallPlugins(plugin.name, source, target, runtime.cwd);
        if (aiMode) {
          process.stdout.write(
            renderAiDone(`Uninstalled ${plugin.name} from ${target}`)
          );
        } else {
          p.log.success(`Uninstalled ${plugin.name} from ${target}`);
        }
      } catch (error) {
        const msg =
          error instanceof Error ? error.message : String(error);
        if (aiMode) {
          process.stdout.write(
            renderAiStep(`Failed to uninstall from ${target}: ${msg}`)
          );
        } else {
          p.log.warn(`Failed to uninstall from ${target}: ${msg}`);
        }
      }
    }
  }

  if (!aiMode && process.stdin.isTTY === true) {
    p.outro(pc.green('Done.'));
  }
  return 0;
};

/**
 * `plugins targets list <plugin>` shows current targets in Clack-note
 * format (TTY) or plain text.
 */
export const runPluginsTargetsListCommand = async (
  args: string[],
  options: PluginsTargetsOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  const pluginName = args[0];
  if (!pluginName) {
    throw new SilentError('Usage: ai-pkgs plugins targets list <plugin>');
  }

  const aiMode = isAICommand(options);
  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();
  const plugin = manifest.plugins.find((pl) => pl.name === pluginName);
  if (!plugin) {
    const available =
      manifest.plugins.map((pl) => pl.name).join(', ') || '(none)';
    throw new SilentError(
      `Plugin "${pluginName}" not found in ai-package.json.\nAvailable: ${available}`
    );
  }

  const targets = plugin.targets ?? [];

  if (!aiMode && process.stdin.isTTY === true) {
    const body =
      targets.length > 0
        ? `targets: ${targets.join(', ')}`
        : 'targets: (none)';
    p.note(body, `Plugin: ${pluginName}`);
  } else {
    process.stdout.write(
      `${pluginName}: ${targets.length > 0 ? targets.join(', ') : '(none)'}\n`
    );
  }

  return 0;
};

/**
 * Resolve, discover, and install a plugin to specified targets.
 */
const installToTargets = async (
  pluginName: string,
  source: string,
  plugin: { provider: string; ref?: string },
  targets: string[],
  projectDir: string,
  aiMode: boolean
): Promise<void> => {
  const registries = createRegistries(projectDir);
  const registryKind =
    plugin.provider === 'file'
      ? 'file'
      : plugin.provider === 'github'
        ? 'github'
        : 'gitlab';
  const registry = getRegistry(registries, registryKind);

  let resolved;
  try {
    resolved = await registry.resolve({
      rawSource: source,
      registry: registryKind,
      ref: plugin.ref,
    });
  } catch {
    if (aiMode) {
      process.stdout.write(
        renderAiStep(`Failed to resolve ${pluginName} for install`)
      );
    } else {
      p.log.warn(`Failed to resolve ${pluginName} for install`);
    }
    return;
  }

  try {
    const { plugins: discovered } = await discoverPlugins(
      resolved.root.rootDir
    );
    const toInstall = discovered.filter((d) => d.name === pluginName);
    if (toInstall.length === 0) return;

    for (const targetId of targets) {
      const target: PluginTarget = {
        id: targetId as 'claude-code' | 'cursor' | 'codex',
        name: targetId,
        detected: true,
        configPath: '',
      };
      await installPlugins(
        toInstall,
        target,
        'user',
        resolved.root.rootDir,
        source,
        projectDir
      );
      if (aiMode) {
        process.stdout.write(
          renderAiDone(`Installed ${pluginName} to ${targetId}`)
        );
      } else {
        p.log.success(`Installed ${pluginName} to ${targetId}`);
      }
    }
  } finally {
    await resolved.root.cleanup?.();
  }
};

import * as p from '@clack/prompts';
import pc from 'picocolors';
import { isAICommand } from '../../cli/ai-mode';
import { renderAiDone, renderAiStep } from '../../cli/ai-output';
import { SilentError } from '../../errors';
import { normalizeList } from '../../install-command';
import { createManifestStore, resolveManifestScope } from '../../manifest';
import { uninstallPlugins } from '../../plugins/installer/uninstall';
import type { PluginsCommandRuntime, PluginsRemoveOptions } from './types';

/**
 * `ai-pkgs plugins remove <plugin...>` removes plugin entries from
 * `ai-package.json`. With `--uninstall`, also cleans agent directories
 * for each persisted target.
 */
export const runPluginsRemoveCommand = async (
  plugins: string[],
  options: PluginsRemoveOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  if (plugins.length === 0) {
    throw new SilentError(
      'Usage: ai-pkgs plugins remove <plugin...> [--uninstall] [--agent <agent>]'
    );
  }

  const aiMode = isAICommand(options);
  if (!aiMode && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin remove'));
  }

  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();

  const byName = new Map(manifest.plugins.map((pl) => [pl.name, pl]));
  const missing = plugins.filter((name) => !byName.has(name));
  if (missing.length > 0) {
    const available =
      manifest.plugins.map((pl) => pl.name).sort().join(', ') || '(none)';
    throw new SilentError(
      `Unknown plugin${missing.length === 1 ? '' : 's'}: ${missing.join(', ')}\nAvailable plugins: ${available}`
    );
  }

  if (options.uninstall === true) {
    const agentFilter = new Set(normalizeList(options.agent));

    for (const name of plugins) {
      const entry = byName.get(name)!;
      const source =
        entry.source ?? `${entry.provider}:${entry.packageId}`;
      const targets =
        agentFilter.size > 0
          ? (entry.targets ?? []).filter((t) => agentFilter.has(t))
          : (entry.targets ?? []);

      for (const target of targets) {
        try {
          await uninstallPlugins(
            name,
            source,
            target,
            manifestScope.projectDir
          );
          if (aiMode) {
            process.stdout.write(
              renderAiDone(`Uninstalled ${name} from ${target}`)
            );
          } else {
            p.log.success(`Uninstalled ${name} from ${target}`);
          }
        } catch (error) {
          const msg =
            error instanceof Error ? error.message : String(error);
          if (aiMode) {
            process.stdout.write(
              renderAiStep(`Failed to uninstall ${name} from ${target}: ${msg}`)
            );
          } else {
            p.log.warn(`Failed to uninstall ${name} from ${target}: ${msg}`);
          }
        }
      }

      if (targets.length === 0 && (entry.targets ?? []).length > 0) {
        if (aiMode) {
          process.stdout.write(
            renderAiStep(
              `No matching targets to uninstall for ${name} (targets: ${(entry.targets ?? []).join(', ')})`
            )
          );
        } else {
          p.log.info(
            `No matching targets to uninstall for ${name} (targets: ${(entry.targets ?? []).join(', ')})`
          );
        }
      }
    }
  }

  await store.removePlugins(plugins);

  if (aiMode) {
    process.stdout.write(
      renderAiDone(
        `Removed ${plugins.length} plugin${plugins.length === 1 ? '' : 's'} from ai-package.json`
      )
    );
  } else {
    p.log.success(
      `Removed ${plugins.length} plugin${plugins.length === 1 ? '' : 's'} from ai-package.json: ${plugins.join(', ')}`
    );
  }

  if (!aiMode && process.stdin.isTTY === true) {
    p.outro(pc.green('Remove complete'));
  }
  return 0;
};

import * as p from '@clack/prompts';
import { canPrompt, isAICommand } from '../../cli/ai-mode';
import { createManifestStore, resolveManifestScope } from '../../manifest';
import type { PluginEntry } from '../../plugins/types';
import type { PluginsCommandRuntime, PluginsListOptions } from './types';

/** JSON output shape for `plugins list --json`. */
export type ListedPlugin = {
  name: string;
  source: string;
  provider: string;
  packageId: string;
  path: string;
  version?: string;
  ref?: string;
  commitSha?: string;
  targets?: string[];
};

/**
 * Render `ai-pkgs plugins list` as grouped, stable ASCII text.
 */
export const formatPluginsList = (plugins: PluginEntry[]): string => {
  const lines = [`manifest plugins: ${plugins.length}`];
  for (const plugin of [...plugins].sort(compareByName)) {
    const source = plugin.source ?? `${plugin.provider}:${plugin.packageId}`;
    const version =
      plugin.ref && plugin.commitSha
        ? ` ${plugin.ref}@${plugin.commitSha.slice(0, 7)}`
        : '';
    const targets =
      plugin.targets && plugin.targets.length > 0
        ? ` [${plugin.targets.join(', ')}]`
        : '';
    lines.push(
      `- ${plugin.name} ${source}${version} ${plugin.path}${targets}`
    );
  }
  return `${lines.join('\n')}\n`;
};

/**
 * List plugins declared in `ai-package.json`.
 */
export const runPluginsListCommand = async (
  options: PluginsListOptions,
  runtime: PluginsCommandRuntime
): Promise<number> => {
  const manifestScope = resolveManifestScope(runtime.cwd, options);
  const store = createManifestStore(
    manifestScope.projectDir,
    manifestScope.manifestPath
  );
  const manifest = await store.read();

  if (options.json === true) {
    process.stdout.write(
      `${JSON.stringify(manifest.plugins.map(toListedPlugin), null, 2)}\n`
    );
    return 0;
  }

  if (canPrompt(options) && !isAICommand(options)) {
    p.intro('AI package plugins');
    if (manifest.plugins.length === 0) {
      p.log.info('No plugins declared in ai-package.json');
    } else {
      p.note(
        formatPluginsListNote(manifest.plugins),
        `Manifest plugins (${manifest.plugins.length})`
      );
    }
    p.outro('Done.');
    return 0;
  }

  process.stdout.write(formatPluginsList(manifest.plugins));
  return 0;
};

const formatPluginsListNote = (plugins: PluginEntry[]): string =>
  [...plugins]
    .sort(compareByName)
    .map((plugin) => {
      const source = plugin.source ?? `${plugin.provider}:${plugin.packageId}`;
      const targets =
        plugin.targets && plugin.targets.length > 0
          ? plugin.targets.join(', ')
          : '(none)';
      return [
        `  ${plugin.name}`,
        `    source: ${source}`,
        `    path: ${plugin.path}`,
        `    targets: ${targets}`,
        ...(plugin.version ? [`    version: ${plugin.version}`] : []),
      ].join('\n');
    })
    .join('\n\n');

const toListedPlugin = (plugin: PluginEntry): ListedPlugin => ({
  name: plugin.name,
  source: plugin.source ?? `${plugin.provider}:${plugin.packageId}`,
  provider: plugin.provider,
  packageId: plugin.packageId,
  path: plugin.path,
  version: plugin.version,
  ref: plugin.ref,
  commitSha: plugin.commitSha,
  targets: plugin.targets,
});

const compareByName = (a: PluginEntry, b: PluginEntry) =>
  a.name.localeCompare(b.name);

import { existsSync, readdirSync } from 'node:fs';
import { resolve } from 'node:path';
import * as p from '@clack/prompts';
import pc from 'picocolors';
import { canPrompt } from '../../cli/ai-mode';
import { SilentError } from '../../errors';
import { normalizeList } from '../../install-command';
import { initPlugin, INIT_AGENTS, INIT_COMPONENTS } from '../../plugins/init';
import type { PluginsInitOptions } from './types';

/**
 * Run `ai-pkgs plugins init` with interactive prompts, overwrite
 * protection, and intro/outro framing.
 */
export const runPluginsInitCommand = async (
  nameArg: string | undefined,
  options: PluginsInitOptions
): Promise<number> => {
  const promptAllowed = canPrompt(options);

  if (!options.ai && process.stdin.isTTY === true) {
    p.intro(pc.bold('Plugin init'));
  }

  let name = nameArg;
  if (!name) {
    if (!promptAllowed) {
      throw new SilentError('Plugin name is required in non-interactive mode');
    }
    const result = await p.text({
      message: 'Plugin name?',
      placeholder: 'my-plugin',
      validate: (value = '') =>
        value.trim().length === 0 ? 'Name is required' : undefined,
    });
    if (p.isCancel(result)) {
      throw new SilentError('Plugin init cancelled');
    }
    name = result;
  }

  let directory: string;
  if (promptAllowed && options.yes !== true) {
    const dirResult = await p.text({
      message: 'Where to create?',
      placeholder: `./${name}`,
      defaultValue: `./${name}`,
    });
    if (p.isCancel(dirResult)) {
      throw new SilentError('Plugin init cancelled');
    }
    directory = resolve(dirResult);
  } else {
    directory = resolve(`./${name}`);
  }

  if (existsSync(directory) && !isEmptyDir(directory)) {
    if (options.force === true) {
      // --force: proceed without prompt
    } else if (promptAllowed) {
      const overwrite = await p.confirm({
        message: `Directory ${directory} already exists with content. Overwrite?`,
        initialValue: false,
      });
      if (p.isCancel(overwrite) || overwrite !== true) {
        throw new SilentError('Plugin init cancelled');
      }
    } else {
      throw new SilentError(
        `Directory ${directory} already exists. Pass --force to overwrite.`
      );
    }
  }

  let agents: string[];
  const agentFlag = normalizeList(options.agent);
  if (agentFlag.length > 0) {
    agents = agentFlag;
  } else if (promptAllowed && options.yes !== true) {
    const selected = await p.multiselect({
      message: 'Target agents?',
      options: INIT_AGENTS.map((a) => ({
        label: a.name,
        value: a.id,
      })),
      initialValues: INIT_AGENTS.map((a) => a.id),
      required: true,
    });
    if (p.isCancel(selected)) {
      throw new SilentError('Plugin init cancelled');
    }
    agents = selected;
  } else {
    agents = INIT_AGENTS.map((a) => a.id);
  }

  let components: string[];
  if (promptAllowed && options.yes !== true) {
    const selected = await p.multiselect({
      message: 'Components to include?',
      options: INIT_COMPONENTS.map((c) => ({
        label: c,
        value: c,
      })),
      initialValues: [...INIT_COMPONENTS],
      required: true,
    });
    if (p.isCancel(selected)) {
      throw new SilentError('Plugin init cancelled');
    }
    components = selected;
  } else {
    components = [...INIT_COMPONENTS];
  }

  const pluginDir = await initPlugin({
    name,
    directory,
    agents,
    components,
  });

  if (!options.ai && process.stdin.isTTY === true) {
    p.log.success(`Plugin scaffolded at ${pluginDir}`);
    p.outro(pc.green('Done.'));
  } else {
    p.log.success(`Plugin scaffolded at ${pluginDir}`);
  }
  return 0;
};

const isEmptyDir = (dir: string): boolean => {
  try {
    return readdirSync(dir).length === 0;
  } catch {
    return true;
  }
};

